const vilenkin6Extra: GdzProblem[  ] = [ { number: '50', page: 31, condition: '50. Какие из дробей 3/8, 8/5, 7/9, 5/4, 11/11, 2/3 являются правильными и какие —', steps: ['Раскладываем: 6 = 2·3, 9 = 3².', 'НОК = 2·3² = 18.'], formulas: ['НОК(6,9) = 18'], answer: '18.' },
  { number: '55', page: 32, condition: '55. Проверьте верность утверждения: «Многозначное число делится на 4, если число,', steps: ['4 = 2², 6 = 2·3, 10 = 2·5.', 'НОК = 2²·3·5 = 60.'], answer: '60.' },
  { number: '60', page: 34, condition: '60. Дано множество дробей {5/7, 8/9, 13/19, 18/18, 5/4, 4/5, 125/126 и 384/383. Составьте подмножество: а) правильных дробей; б) неправильных', steps: ['Приводим к общему знаменателю 10: 3/5 = 6/10.', '6/10 < 7/10.'], answer: '3/5 < 7/10.' },
  { number: '65', page: 36, condition: '65. Какие цифры следует поставить вместо звёздочек в записи 2*5, 46*, *14, чтобы получившиеся числа делились на', steps: ['Знаменатели одинаковые: (1+5)/6 = 6/6 = 1.'], answer: '1.' },
  { number: '70', page: 38, condition: '70. Собрали 2 ц яблок и часть из них разложили в 9 одинаковых ящиков. Могло ли после этого', steps: ['(7−3)/8 = 4/8 = 1/2.'], answer: '1/2.' },
  { number: '80', page: 42, condition: '80. Всегда ли запись числа, делящегося на 5, оканчивается цифрой 5? Может ли число, не делящееся', steps: ['НОК(4,6) = 12. 1/4 = 3/12, 1/6 = 2/12.', '3/12 + 2/12 = 5/12.'], answer: '5/12.' },
  { number: '90', page: 46, condition: '90. В записи *723, 5*36, 111* вместо звёздочки поставьте такие цифры, чтобы получившиеся числа делились на', steps: ['НОК(4,6) = 12. 3/4 = 9/12, 1/6 = 2/12.', '9/12 − 2/12 = 7/12.'], answer: '7/12.' },
  { number: '100', page: 50, condition: '100. Может ли площадь квадрата выражаться простым числом, если длина его стороны выражается', steps: ['2/3 · 3/4 = (2·3)/(3·4) = 6/12 = 1/2.'], answer: '1/2.' },
  { number: '110', page: 55, condition: '110. Длина и ширина прямоугольного параллелепипеда выражаются натуральным числом', steps: ['5/6 : 5/3 = 5/6 · 3/5 = 15/30 = 1/2.'], answer: '1/2.' },
  { number: '120', page: 60, condition: '120. С помощью таблицы простых чисел, помещённой на форзаце учебника, выберите из чисел 122, 132, 153, 157, 187, 499, 550, 621, 881, 865 и 909 простые', steps: ['2⅓ = 7/3, 1⅔ = 5/3.', '7/3 + 5/3 = 12/3 = 4.'], answer: '4.' },
  { number: '155', page: 82, condition: '155. Запишите все правильные дроби со знаменателем 12, у которых числитель и знаменатель — взаимно простые', steps: ['Из пропорции: x = 2·9/3 = 18/3 = 6.'], formulas: ['a/b = c/d → ad = bc'], answer: 'x = 6.' },
  { number: '160', page: 84, condition: '160. Существует ли куб, ребро которого выражается натуральным числом и у которого: а) сумма', steps: ['Составляем пропорцию: 3/150 = 5/x.', 'x = 5·150/3 = 250 руб.'], answer: '250 руб.' },
  { number: '170', page: 88, condition: '170. Представьте в виде обыкновенной дроби числа 0,3; 0,13; 0,2 и в виде десятичной дроби числа 3/8; 4 1/2; 3', steps: ['20% = 0,2. 0,2 · 350 = 70.'], answer: '70.' },
  { number: '180', page: 92, condition: 'Число 60 составляет 75% некоторого числа. Найдите это число.', steps: ['x · 0,75 = 60. x = 60 / 0,75 = 80.'], answer: '80.' },
  { number: '285', page: 134, condition: '285. Можно ли представить в виде десятичной дроби: 2/5; 4/25; 2/3; 4/7; 12/15; 9/18? В каком случае обыкновенную дробь можно представить в виде', steps: ['Складываем числа с одинаковым знаком: берём сумму модулей, ставим общий знак.', '|−5| + |−3| = 8. Знак «−». Ответ: −8.'], answer: '−8.' },
  { number: '290', page: 136, condition: 'Вычислите: (−7) − (−4).', steps: ['Вычитание — прибавление противоположного: (−7) + 4 = −3.'], answer: '−3.' },
  { number: '300', page: 140, condition: '300. Найдите значение выражения: 1) 4 4/33 + 3 7/33; 2) 5 13/18 - 2 7/18; 3) 23/48 - 13/48 + 5/48; 4) 7/45 + 14/45 -', steps: ['«Минус» на «плюс» = «минус». (−3)·5 = −15.'], answer: '−15.' },
  { number: '310', page: 144, condition: 'Вычислите: (−6) · (−4).', steps: ['«Минус» на «минус» = «плюс». 6·4 = 24.'], answer: '24.' },
  { number: '320', page: 148, condition: '320. Через узкую трубу бассейн наполняется за 10 ч, а через широкую — за 4 ч. Какая труба даёт', steps: ['«Минус» на «минус» = «плюс». 24 : 6 = 4.'], answer: '4.' },
  { number: '425', page: 204, condition: '425. Для экспедиции, работающей в тайге, сбросили с вертолёта упаковку с продуктами, которая', steps: ['x = 3 — отступаем 3 единицы вправо по оси x.', 'y = −2 — отступаем 2 единицы вниз по оси y.'], answer: 'Точка A находится в IV четверти координатной плоскости.' } ]

