const ladyzhenskaya6Solutions: GdzProblem[] = [
  { number: '1', page: 3, condition: '1. Прочитайте. В каком предложении выражена главная мысль текста? В каких утверждениях автора содержится её обоснование? Какой вывод содержится в цитируемых словах Н. Гоголя? К какому функциональносмысловому типу речи можно отнести этот текст? Русский язык — один из самых развитых и богатых языков мира. Он звучен и мелодичен: в нём на сто звуков приходится примерно восемьдесят звуков с голосом — гласных и звонких согласных. Русский язык располагает большим запасом слов. В нём много синонимов. С их помощью точно и ярко выражаются все оттенки мысли и чувства. В русском языке много способов образования новых слов, и поэтому он обладает неиссякаемыми источниками пополнения своего словарного запаса. В русском языке, говорил Николай Васильевич Гоголь, «все тоны и оттенки, все переходы звуков от самых твёрдых до самых нежных и мягких; он беспределен и может, живой как жизнь, обогащаться ежеминутно».', steps: ['Тема: роль языка в жизни людей.', 'Это текст, т.к. предложения связаны по смыслу: каждое продолжает мысль предыдущего, они объединены одной темой.'], answer: 'Тема — роль языка; это текст, т.к. предложения связаны по смыслу и теме.' },
  { number: '2', page: 4, condition: '2. Ответьте на вопрос, опираясь на текст из упр. 1: «В чём заключается богатство и выразительность русского языка?» Вы можете использовать дополнительные источники информации. Запишите свой ответ.', steps: ['Вступление: значение родного языка.', 'Основная часть: примеры богатства языка (слова, пословицы, стихи).', 'Заключение: важность изучения языка.'], answer: 'Пример: «Русский язык — один из богатейших языков мира. В нём тысячи слов, пословиц и поговорок. Знать родной язык — значит уважать свой народ...»' },
  { number: '3', page: 4, condition: '3. Прочитайте высказывания о русском языке. Какой общей мыслью объединены эти высказывания? Какие характерные особенности русского языка отмечены в них? Как вы думаете, эпиграф к разделу подтверждает общую мысль высказываний? Подготовьтесь записать их под диктовку (см. памятку на с. 205). 1. Русский язык необыкновенно богат. (В. Белинский) 2. Для всего в русском языке есть великое множество хороших слов. (К. Паустовский) 3. Русский язык в умелых руках и в опытных устах — красив, певуч, выразителен, гибок, послушен, ловок и вместителен. (А. Куприн) 4. Берегите наш язык, наш прекрасный русский язык, этот клад, это достояние, переданное нам нашими предшественниками. (И . Тургенев)', steps: ['Кто? что? — язык (подлежащее).', 'Что делает? — помогает (сказуемое).', 'Грамматическая основа: язык помогает.'], answer: 'Грамматическая основа: язык помогает.' },
  { number: '4', page: 5, condition: 'Используя высказывание о языке писателя К. Паустовского (см. упр. 3) как тезис, постройте рассуждение. Приведите примеры из произведений художественной литературы.', steps: ['весна — весны (Е проверяется).', 'трава — травы (А проверяется).', 'лесной — лес (Е проверяется).', 'города — город (О проверяется).'], answer: 'весна (весны), трава (травы), лесной (лес), города (город).' },
  { number: '5', page: 5, condition: 'Развитый, развитой, развитый — это три разных слова или варианты произношения одного? Проверьте себя по словарям. В каких словарях вы нашли нужные ответы?', steps: ['Читаем высказывание.', 'Объясняем: что хотел сказать автор, в чём главная мысль, почему это важно.'], answer: 'Ответ зависит от конкретного высказывания в учебнике. Объясняем смысл своими словами.' },
  { number: '6', page: 6, condition: 'Найдите и запишите фрагмент из любого художественного произведения, чтобы подтвердить характеристику русского языка как развитого и богатого. Объясните, почему вы сделали такой выбор.', steps: ['Существительное: книга, дом, река.', 'Прилагательное: красивый, большой, синий.', 'Глагол: читать, идти, говорить.', 'Наречие: быстро, тихо, вчера.', 'Числительное: три, десятый.', 'Местоимение: я, он, этот.', 'Предлог: в, на, за. Союз: и, но, а. Частица: не, же.'], answer: 'Самостоятельные: сущ., прил., гл., нареч., числит., мест. Служебные: предлог, союз, частица.' },
  { number: '7', page: 6, condition: 'Как вы думаете, почему в почтовых отправлениях необходимо указывать адреса, сведения об отправителях и получателях на русском языке? Почему использование русского языка обязательно в документах об образовании? Представители каких народностей проживают в вашем крае? Какой язык для них родной? На каком языке вы общаетесь с ними?', steps: ['птицы — подлежащее (существительное, им. пад.).', 'запели — сказуемое (глагол пр. вр., мн.ч.).', 'ранним утром — обстоятельство времени (когда?).', 'весёлые — определение (какие?).', 'песни — дополнение (что?).'], answer: 'Птицы — подлежащее; запели — сказуемое; ранним утром — обстоятельство; весёлые — определение; песни — дополнение.' },
  { number: '8', page: 7, condition: 'Прочитайте научно-учебный текст § 3, данный на с. 6, и составьте его простой план. Оформите информацию о разновидностях литературной нормы с помощью схемы (кластера) для презентации в классе. Подберите примеры.', steps: ['небо — НЕ является частью корня, слитно.', 'нехотел — раздельно: не хотел (глагол).', 'некрасивый — слитно: можно заменить синонимом «уродливый».', 'не читал — раздельно (глагол).'], answer: 'небо (часть корня); не хотел, не читал (глаголы — раздельно); некрасивый (синоним — слитно).' },
  { number: '9', page: 8, condition: 'Произнесите слова, соблюдая орфоэпические нормы. Алфавит, ателье, ворота, досуг, квартал, конечно, облегчить, свекла, скучный, углубить, звонит, легче, шарфы, намерение, копировать, кафе.', steps: ['цыплёнок — ЦЫ (после Ц в корне — И, но исключение: цыган, цыплёнок, цыкнуть, цыц).', 'жизнь — ЖИ пишется с И.', 'шёпот — ШЁ (под ударением Ё в корне).', 'часы — ЧА пишется с А.'], answer: 'цыплёнок (исключение), жизнь (жи-ши), шёпот (ё под ударением), часы (ча-ща).' },
  { number: '10', page: 8, condition: 'Рассмотрите схему рассуждения. Выделите тезис (то, что нужно доказать), аргументы (доказательства) и вывод. Используя данную схему, порассуждайте, почему необходимо изучать литературу, биологию, математику и другие школьные предметы.', steps: ['заморозки: за- (приставка) + мороз (корень) + -к- (суффикс) + -и (окончание).', 'перечитать: пере- + чит + -а- + -ть.', 'подснежник: под- + снеж + -ник + ∅ (нулевое окончание).'], answer: 'за|мороз|к|и; пере|чит|а|ть; под|снеж|ник|∅.' },
  { number: '11', page: 9, condition: 'Расставьте ударение, обозначьте букву (там, где это необходимо) в фамилиях деятелей русской культуры. В случае затруднения обращайтесь к различным источникам информации. Прочитайте, соблюдая литературные нормы. Бальмонт Константин Дмитриевич — поэт; Искандер Фазиль Абдулович — писатель; Коненков Сергей Тимофеевич — скульптор; Куинджи Архип Иванович — художник; Майков Аполлон Николаевич — поэт; Новиков Николай Иванович — русский просветитель; Ожегов Сергей Иванович — языковед; Одоевский Владимир Фёдорович — писатель; Соколов-Микитов Иван Сергеевич — писатель.', steps: ['Синонимы — слова близкие по смыслу: огромный, крупный, гигантский, громадный, великий.'], answer: 'огромный, крупный, гигантский, громадный, величественный.' },
  { number: '12', page: 9, condition: 'К словам из левой колонки подберите подходящие по смыслу слова из правой колонки, запишите получившиеся словосочетания. табун стая отара стадо гуси овцы коровы лошади', steps: ['Антонимы — противоположные по смыслу слова.', 'радость — горе (печаль). добро — зло. утро — вечер. быстрый — медленный.'], answer: 'горе, зло, вечер, медленный.' },
  { number: '13', page: 10, condition: 'Поставьте имена существительные в форму именительного падежа множественного числа и распределите их по двум колонкам. -а, -я -ы, -и Адрес, договор, мастер, подпись, почерк, приз, профессор, торт, тренер.', steps: ['Фразеологизм — устойчивое сочетание.', '«бить баклуши» буквально = раскалывать обрубки дерева (лёгкая работа).', 'Переносное значение: бездельничать, праздно проводить время.'], answer: 'Бездельничать, праздно проводить время.' },
  { number: '14', page: 10, condition: 'Запишите словосочетания, выбирая из скобок подходящее по смыслу слово. Обозначьте в словосочетаниях главное слово. Волосы (русые, карие), (одеть, надеть) очки, (доверчивый, доверительный) тон разговора, похвалить за (поступок, проступок), транспорт (водяной, водный, водянистый), день (ветреный, ветряной, ветряный).', steps: ['земля = планета: путешествие вокруг Земли.', 'земля = суша: выйти на землю.', 'земля = почва: плодородная земля.', 'земля = страна: родная земля.'], answer: 'планета Земля; выйти на землю; плодородная земля; родная земля.' },
  { number: '15', page: 11, condition: 'Спишите, вставляя пропущенные буквы в корнях слов. Обменяйтесь работами с соседом по парте, проверьте друг у друга правильность выполнения задания. Сп..шите условие задачи, сп..шите к отправлению поезда; зап..вать в строю, зап..вать лекарство; пол..скать в 9 реке, пол..скать щенка; привести на лошади, привести за руку из детсада.', steps: ['Чередования: -ЛАГ-/-ЛОЖ-: перед Г — А, перед Ж — О.', 'излОжение (перед Ж → О), предлАгать (перед Г → А).', '-ГАР-/-ГОР-: без ударения — ГОР.', 'загОрать (без ударения → О), загАр (под ударением → А).'], answer: 'изложение, предлагать; загорать (без ударения), загар (ударный).' },
  { number: '16', page: 12, condition: 'Диктант. Баске..бол, брош..ра, б..рюзовый, ..дание, к..рзина, л..ловый, параш..т, про(ф, фф)е(с, сс)ия, ра..цвет, ра..чёт, сп..ртакиада, трен..роват(?)ся.', steps: ['Повествование — события сменяют друг друга (когда? что случилось?).', 'Описание — признаки предмета или явления (какой?).', 'Рассуждение — мысль объясняется (почему? что из этого следует?).'], answer: 'Тип определяется по содержанию: если события — повествование; признаки — описание; доказательства — рассуждение.' },
  { number: '17', page: 12, condition: 'Прочитайте текст. Почему Лев Владимирович Щерба сравнил литературный язык «с хорошо настроенным музыкальным инструментом»? Как вы понимаете выражение «обработанный язык»? Перескажите текст. В своё время академик Л. В. Щерба сказал, что литературный язык можно сравнить с хорошо настроенным музыкальным инструментом. На нём можно играть сложнейшие мелодии, но для настройки этого инструмента нужен мастер. Расстроенный язык можно сравнить с расстроенным инструментом. Конечно, мы можем думать, что незачем нам все эти смысловые и стилистические тонкости, ведь мне главное — пообщаться, меня поймут. Но обработанный язык со своей стилистической вершиной существует как великолепный музыкальный инструмент, который можно использовать для передачи тончайших нюансов мысли, движения чувств, отношении между людьми... (Л. Скворцов. «Экология слова, или Поговорим о культуре русской речи»)', steps: ['уста — губы.', 'очи — глаза.', 'ланиты — щёки.', 'глаголить — говорить.'], answer: 'уста → губы; очи → глаза; ланиты → щёки; глаголить → говорить.' },
  { number: '18', page: 13, condition: 'Определите род имён существительных и составьте с ними словосочетания «прилагательное + существительное». Значение незнакомых для вас слов установите по словарю. Какой словарь вам понадобится? Суши, картофель, авокадо, желе, пюре, какао, сулугуни, кофе, манго, безе, эскимо, фасоль, салями, мацони, фойе, маэстро, конфетти, рояль, тюль.', steps: ['Согласование: красивый цветок (прил. согласуется с сущ.).', 'Управление: любить книги (сущ. в пад. управляется глаг.).', 'Примыкание: бежать быстро (нареч. примыкает к глаг.).'], answer: 'Согласование: красивый цветок; управление: любить книги; примыкание: бежать быстро.' },
  { number: '19', page: 13, condition: 'Поставьте имена существительные в форму родительного падежа множественного числа. Проверьте правильность выполнения задания по словарям. Апельсин, мандарин, помидор, кочерга, усадьба, сапог, ботинок, валенок, носок, чулок, грамм, килограмм, гектар, рельс, солдат, полотенце, зеркальце, блюдце, няня, цапля.', steps: ['Перед П (глухой) → С: беСполезный.', 'Перед Ц (глухой) → С: раСценки.', 'Перед П (глухой) → С: ниСпровергать.'], answer: 'беСполезный, раСценки, ниСпровергать.' },
  { number: '20', page: 14, condition: 'В какой речевой ситуации (на экзамене, в театре...) вы могли бы услышать данные предложения? Почему? Соблюдена ли в них литературная норма? 1. Я бы хотела быть модельершей. 2. Входные билеты проверяли две билетёрши. 3. Главную партию исполнял мой любимый балерун.', steps: ['1 скл. (ж.р., окончание -а/-я).', 'И.п. — дорога, Р.п. — дороги, Д.п. — дороге, В.п. — дорогу, Т.п. — дорогой, П.п. — о дороге.'], answer: 'дорога, дороги, дороге, дорогу, дорогой, о дороге.' },
  { number: '21', page: 14, condition: 'В повести Ю. Яковлева «Мальчик с коньками» описывается ситуация, когда школьник увидел, что мужчине стало плохо. Мальчик помог человеку дойти до дома и позвонил в службу скорой помощи. Прочитайте диалог по ролям. Какова цель разговора? Достиг ли цели мальчик? Почему? — Скорая слушает. Что у вас? — Тётенька, — заговорил мальчик, — человеку плохо. — Фамилия? — бесстрастно спросил голос. — Чья фамилия? — Больного. — Он не больной, он раненый. — Где ранен? — На фронте, под Орлом. Наверное, там, в скорой помощи, так привыкли ко всяким необычностям, что даже не поинтересовались, при чём здесь Орёл. Нетерпеливый голос продолжал: — Где находится пострадавший? — Дома. — Адрес? Мальчик запнулся. Он не знал адреса. Он так и сказал: — Я не знаю адреса. — Так что же ты вызываешь скорую помощь? На деревню к дедушке, что ли, ехать? Узнай адрес и перезвони. В трубке раздались короткие гудки.', steps: ['ходить → ходьба.', 'бегать → бег, беготня.', 'плавать → плавание.', 'читать → чтение.'], answer: 'ходьба, бег, плавание, чтение.' },
  { number: '22', page: 15, condition: 'Обсудите с одноклассниками ситуацию, описанную в упр. 21. Как бы вы поступили на месте мальчика? Язык располагает богатым набором средств, позволяющих найти нужные слова для объяснения сути дела любому человеку. Среди языковых средств необходимо выбирать такие, которые лучше всего выполняют поставленные задачи общения. Задачи общения могут быть выражены с помощью глаголов попросить, сообщить, пригласить, поздравить, посоветовать, извиниться и др.', steps: ['Прил. от сущ. с суффиксом -АН-/-ЯН- → одна Н (искл.: стеклянный, оловянный, деревянный).', 'кожаный — одна Н (кожа + -АН-).', 'деревянный, стеклянный, оловянный — ДВЕ Н (исключения!).'], answer: 'деревянный, кожаный, стеклянный, оловянный.' },
  { number: '23', page: 15, condition: 'Познакомьтесь с высказыванием языковеда С. Ожегова. Подтвердите справедливость высказывания учёного своими примерами. Культура речи заключается не только в следовании нормам языка. Она заключается ещё и в умении найти не только точное средство для выражения своей мысли, но и наиболее доходчивое (т. е. наиболее выразительное) и наиболее уместное (т. е. самое подходящее для данного случая) и, следовательно, стилистически оправданное. Знание правил речевого этикета и умение ими пользоваться — важная часть культуры речи.', steps: ['Однородные: огурцы, помидоры, морковь, картофель.', 'Перед «и» с одним повторяющимся союзом запятая не ставится; остальные разделяются запятыми.', 'На огороде росли огурцы, помидоры, морковь и картофель.'], answer: 'На огороде росли огурцы, помидоры, морковь и картофель.' },
  { number: '24', page: 16, condition: 'Составьте текст-описание «Моё любимое время года» (6–8 предложений).', steps: ['1. Назовите время года и почему оно любимое.', '2. Опишите природу: цвета, звуки, запахи.', '3. Расскажите, чем любите заниматься в это время.', '4. Заключение: общее впечатление.'], answer: 'Личное сочинение. Используйте прилагательные, сравнения, образные выражения.' },
  { number: '25', page: 16, condition: 'Прочитайте текст, соблюдая необходимую интонацию. Сформулируйте и запишите его тему и главную мысль. Назовите средства выразительности, которые используются в тексте. Человеческие поступки — в слове, даже во взгляде. Слово — тончайшее прикосновение к сердцу; оно может статьи нежным поцелуем, и благоухающим цветком, и живой водой, возвращающей веру в добро, и острым ножом, ковырнувшим нежную ткань души, и раскалённым железом, ушатом холодной воды, и комьями вонючей грязи — всё это может нести в себе человеческое слово; слово оборачивается самыми неожиданными поступками даже тогда, когда его нет, а есть молчание. Там, где необходимо острое, прямое, честное слово, иногда мы видим позорное молчание, это самый гнусный поступок — предательство. Бывает и наоборот. Предательством становится слово, которое должно молчать, храня тайну. Мудрое и доброе слово доставляет радость, глупое и злое, необдуманное и бестактное слово приносит беду. Словом можно убить и оживить, ранить и излечить, посеять смятение, безнадёжность и одухотворить, рассеять сомнения и повергнуть в уныние, сотворить улыбку и вызвать слёзы, породить веру в человека заронить неверие, вдохновить на труд и привести в оцепенение силы души. Твоё злое, неудачное, бестактное, попросту глупое слово может оскорбить, огорчить, ошеломить, потрясти человека. Умей сообразить и почувствовать, когда человеку, с которым ты соприкасаешься, нужно, чтобы ты говорил, а когда ему крайне необходимо, чтобы ты молчал. Одно-единственное твоё слово может создать у людей мнение о тебе как о хаме или невежде, пустопорожнем болтуне или хвастуне. <...> Есть слова яркие и неугасающие, как вечные звёзды, указывающие человеку путь. Стремитесь к тому, чтобы ваши слова были путеводными звёздами. Не будет огонька у вас — вам никогда не зажечь его у других. <...> Каждое наше слово должно нести в себе добро, справедливость, красоту.5 (В. Сухомлинский. «Как воспитать настоящего человека»)', steps: ['"ихние" — нет такой формы; правильно: их вещи.', '"ложить" — неправильный глагол; правильно: класть на стол.', '"более красивее" — двойное сравнение; правильно: более красивый (или красивее).'], answer: 'их вещи; класть на стол; более красивый (красивее).' },
  { number: '30', page: 18, condition: 'Послушайте стихотворение А. Кондратьева «Гном и Гром». Какой звук повторяется в стихотворении чаще всего? Как вы думаете, почему? И в лесу, И возле дома Умный Гном боится Грома! Загрохочет в тучах Гром — Умный Гном сейчас же в дом. Ведь всегда у Гнома дома Есть громоотвод от Грома!', steps: [ 'Три однородных подлежащих: берёзы, дубы, сосны.', 'Перед союзом «и», соединяющим последнее, запятая не ставится.', 'На поляне росли берёзы, дубы и сосны.' ], answer: 'На поляне росли берёзы, дубы и сосны.' },
  { number: '40', page: 22, condition: 'Прочитайте выразительно стихотворение. Какова его главная мысль? Выпишите по 2—3 изменяемых слова, основа которых состоит из: а) корня; б) корня и суффикса; в) приставки, корня и суффикса. В выписанных словах обозначьте основу и её части (морфемы), окончание. МАЛЕНЬКИЕ СТАНЦИИ РОССИИ Маленькие станции России, Полевые, к северу лесные, С тополиной вьюгой по весне, Золотые осенью, зимою В голубых сугробах под луною, Примут поезд, Промелькнут2 в окне — И земля покажется красивей, Потому что за спиной всегда Маленькие станции России На пути в большие города. (А. Чепуров)', steps: [ 'Витязь — устаревшее слово (рыцарь, воин).', 'Сейчас употребляется редко, заменяется словом «воин», «рыцарь».' ], answer: 'Витязь — устаревшее слово.' },
  { number: '50', page: 26, condition: 'Прочитайте. Запишите группами слова известных вам самостоятельных частей речи. Обозначьте в записанных прилагательных безударные окончания. ...Речка бежит3 по ровной долине3 или по широкому лугу. Извилистые берега её обрастают местами лозняком, вербою и ольхой, а местами осокой и другими береговыми травами; дно её ровно и гладко, и глубина почти везде одинакова. (С. Аксаков. « Записки ружейного охотника Оренбургской губернии»)', steps: [ 'Официальное обращение, деловой тон.', 'Официально-деловой стиль.' ], answer: 'Официально-деловой стиль.' },
  { number: '85', page: 48, condition: '85. Какова в действительности задача советов Г. Остера из его книги «Вредные советы»? Кому эти вредные советы можно адресовать? Никогда не мойте руки, Шею, уши и лицо. Это глупое занятье Не приводит ни к чему. Вновь испачкаются руки, Шея, уши и лицо. Так зачем же тратить силы, Время попусту терять? Стричься тоже бесполезно, Никакого смысла нет. К старости сама собою Облысеет голова.', steps: [ 'Тема — о чём говорится (например, о весне).', 'Основная мысль — что хочет сказать автор (природа пробуждается).' ], answer: 'Тема: весна. Основная мысль: природа оживает после зимы.' },
  { number: '95', page: 52, condition: '95. Прочитайте текст. Каковы его тема и главная мысль? Определите форму речи. Между кем происходит общение? Бабушка почитала-почитала книжку «Воспитание ребёнка в семье» и говорит: — Серёжа, подойди сюда. Сядь. Замечаю я, что ты както замкнулся в себе, отдалился от своих сверстников, а? Объясни мне, пожалуйста, почему это так? — А мне никакие сверстники не нужны, — независимо сказал Серёжка. — Я и один проживу. — Почему? — А потому, что с ними со всеми поссорился. — Со всеми? — Со всеми, — подтвердил Серёжка. — Что ты с ними не поделил? С Борисом, например? — Значит так, — Серёжка загнул палец, — с Борисом мы поссорились через комара. — Как же так... через комара? — Да! Вот когда комары были, кусали они нас, кусали, а мы и не знали, куда они садятся. А оказывается, надо подставить руку, он сядет и вопьётся, а сам весь прозрачный, видно, что у него внутри делается, как кровь прямо ему в желудок проходит. Тут комары перестали на нас садиться, и вдруг прилетел один — громадный, весь полосатый, хотел сесть на меня, а Борис свою руку к нему тянет... — И тебе жалко стало комара!.. — ужаснулась бабушка. — Не жалко, а пускай не лезет, — объяснил ей Серёжка. — Жди, когда к тебе прилетит, а чужого комара нечего переманивать! Да я б не поссорился, но только он потом потерял зуб. — Какой зуб? — Мой! Мне его врач выдернул и отдал. — Подожди, Серёжа, — взялась за виски бабушка, — ты мне совсем голову заморочил... Я не пойму... (Ю . Третьяков. «Толстый мальчишка»)', steps: [ 'ё — в начале слова = [й][о].', 'л — [л], к — [к], а — [а].', '[й][о][л][к][а].' ], answer: '[ й\'олка ].' },
  { number: '105', page: 57, condition: '105. Найдите и исправьте недочёты в выборе средств связи между предложениями. Поясните написание слов с пропуском букв и со скобками. 1. На углу улиц., строители возводит многоэтажное здание. В этом здании намечает(?)ся открыть дом бытовых услуг. 2. В мастерской при доме бытовых услуг р..монтируют мужскую и женскую одежду. Р..монтируют её квалифицированные м..стера. 3. На фабрике делают шкафы, столы, диваны. Шкафы, столы, диваны на фабрике выпускают высокого качества. Для справок: здание — оно, дом; ремонтировать — чинить; шкафы, столы, диваны — мебель.', steps: [ 'пере- — приставка.', '-чит- — корень.', '-а- — суффикс.', '-ть — суффикс инфинитива.' ], answer: 'пере-чит-а-ть.' },
  { number: '145', page: 87, condition: '145. Прочитайте отрывок из повести К. Паустовского о Мещёрском крае. Какие чувства и мысли он вызывает? Какова общая характеристика природы? Можно ли назвать его художественным описанием? Назовите те предметы, которые попали в поле зрения писателя. Что именно сказано о каждом предмете? С помощью каких языковых средств писатель характеризует каждый из предметов описания? Осень в прошлом году стояла — вся напролёт — сухая и тёплая. Берёзовые рощи долго не желтели. Долго не увядала трава. Только голубеющая дымка (её зовут в народе «мгла») затягивала плёсы на реке и отдалённые леса. Мгла то сгущалась, то бледнела. Тогда сквозь неё проступали, как через матовое стекло, туманные видения вековых ракит на берегах, увядшие пажити и полосы изумрудных озимей.', steps: [ 'тонна — нн (корень тонн-).', 'ванна — нн (корень ванн-).', 'Проверить нельзя — словарные слова.' ], answer: 'тонна, ванна — удвоенные нн.' },
  { number: '155', page: 92, condition: 'Найдите причастие в предложении: «Написанное письмо лежало на столе».', steps: [ 'написанное — отвечает на вопрос «какое?», образовано от глагола «написать».', 'Это страдательное причастие прошедшего времени.' ], answer: 'написанное — причастие.' },
  { number: '165', page: 97, condition: '165. Сочинение. Опишите по выбору помещение, используя составленный план и собранные материалы (см. упр. 164). Озаглавьте сочинение. Определите его главную мысль. Какой функциональной разновидностью языка вы воспользуетесь? Какие из синонимов в рамках вам пригодятся для описания? Подумайте о том, как можно было бы улучшить сочинение. Отредактируйте его, перепишите. Ставить Устанавливать Живописный Картинный Декоративный', steps: [ 'Главное слово: бежать (глагол).', 'Зависимое: быстро (наречие, неизменяемое).', 'Тип связи: примыкание.' ], answer: 'Примыкание.' },
  { number: '225', page: 128, condition: '225. Назовите средства выразительности, которые используются в тексте. Какую роль они играют? Тут был снегирь. Важный, сытый, круглый, ни дать ни взять мыльный пузырь, если ты его выдуваешь на заходе солнца, когда оно красное. Тут же были и крючконосые клесты, и щекастые синички, и славочки, такие свежие и пухлые на взгляд, что, кажется, прямо живую бы съел... шутя, конечно... Иволга тоже была крупная и зелёная, как болото, и чёрные учёные дрозды. (В. Драгунский. «Белые амадины»)', steps: [ 'И.п. — книга.', 'Р.п. — книги.', 'Д.п. — книге.' ], answer: 'книга, книги, книге.' },
  { number: '235', page: 133, condition: '235. Найдите и выпишите 2—3 примера профессионализмов из любых художественных произведений. Объясните, почему они используются именно в этих текстах.', steps: [ 'дерево → деревья (ья).', 'окно → окна (а).', 'небо → небеса (неправильная форма).' ], answer: 'деревья, окна, небеса.' },
  { number: '245', page: 138, condition: '245. Проведите исследование на тему «Диалектные слова нашего края (области, села)». Какое место среди других групп слов занимают диалектные слова? Как часто они употребляются? Подготовьте проект по результатам исследования в виде словаря диалектных слов или в виде рассказов с использованием диалектизмов.', steps: [ 'Ляжет — правильная форма (лягу, ляжешь, ляжет).', 'Ошибочная форма: «ложет» — не существует.' ], answer: 'Он ляжет — правильно.' },
  { number: '255', page: 143, condition: '255. Подберите к словам с заимствованными корнями синонимы, являющиеся исконно русскими по происхождению. Составьте с 2—3 парами слов словосочетания, обозначьте главное слово в каждом из них. презентация деструктивный консенсус интегрировать коммуникабельный имидж позитивный санкционировать Для справок: представление, положительный, объединять, облик, общительный, согласие, признавать законным, разрушительный.', steps: [ 'Непроизносимая согласная в: чу-вство → [ч\'уства].', 'В: [ч\'][у][с][т][в][а].' ], answer: '[ ч\'уства ].' },
  { number: '265', page: 148, condition: '265. Прочитайте. Почему третьеклассники не смогли правильно объяснить значение слов? Что же в действительности обозначают эти слова? Проверьте себя по «Толковому словарю». Выпишите слова с выделенными буквами, объясните выбор орфограмм.', steps: [ 'путь — м.р., оканч. нулевое → разносклоняемое (3 скл. + особое).', 'ночь — ж.р., нулевое оконч. → 3-е скл.', 'дядя — м.р., оканч. -я → 1-е скл.' ], answer: 'путь — особое скл.; ночь — 3 скл.; дядя — 1 скл.' },
]
