const spotlight6Solutions: GdzProblem[  ] = [ { number: '1', page: 4, condition: 'Ex. 1. Match the words with the pictures: bus, train, plane, bike.', steps: ['bus — автобус (обычно изображён городской транспорт)', 'train — поезд, plane — самолёт, bike — велосипед.', 'Соответствие определяется по контексту рисунка в учебнике.'], answer: 'bus — автобус, train — поезд, plane — самолёт, bike — велосипед.' },
  { number: '2', page: 4, condition: 'Ex. 2. Fill in: <i>by, on, in</i>. "I go to school ___ foot."', steps: ['Предлог движения пешком — on foot (устойчивое выражение).', '"I go to school on foot."'], answer: 'on foot.' },
  { number: '5', page: 6, condition: 'Ex. 5. Complete with the correct form of "be": He ___ a student.', steps: ['He (он) — третье лицо единственного числа.', 'Форма глагола be в Present Simple для he/she/it — is.'], answer: 'He <b>is</b> a student.' },
  { number: '8', page: 8, condition: 'Ex. 8. Translate into English: «Я люблю читать книги».', steps: ['Я — I, люблю — like/love, читать — to read, книги — books.', 'I like to read books. / I love reading books.'], answer: 'I like to read books.' },
  { number: '26', page: 20, condition: 'Ex. 1. Write the plural of the nouns: class, teacher, subject.', steps: ['class → classes (после ch, sh, s, x, z добавляем -es).', 'teacher → teachers (+ s).', 'subject → subjects (+ s).'], answer: 'classes, teachers, subjects.' },
  { number: '30', page: 22, condition: 'Ex. 5. Use Present Simple. "She (study) English every day."', steps: ['She — 3-е лицо ед.ч. В Present Simple добавляем -es/-s к глаголу.', 'study → studies (после согласной + y меняем y → i + es).'], answer: 'She <b>studies</b> English every day.' },
  { number: '51', page: 36, condition: 'Ex. 1. Describe your house. Write 3 sentences using "there is / there are".', steps: ['There is a living room in my house.', 'There are two bedrooms upstairs.', 'There is a small garden near the house.'], answer: 'Пример: There is a living room. There are two bedrooms. There is a kitchen.' },
  { number: '76', page: 52, condition: 'Ex. 1. Fill in: <i>near, next to, opposite, between</i>. "The bank is ___ the park."', steps: ['Near — рядом, next to — рядом с, opposite — напротив, between — между.', 'По контексту предложения и рисунка выбирается подходящий предлог.'], answer: 'Зависит от карты: например, "The bank is <b>opposite</b> the park."' },
  { number: '101', page: 68, condition: 'Ex. 1. Write comparative forms: big, expensive, good.', steps: ['big → bigger (короткое прилагательное: удвоение + -er).', 'expensive → more expensive (длинное: more + прилагательное).', 'good → better (неправильная форма).'], answer: 'bigger, more expensive, better.' },
  { number: '126', page: 84, condition: 'Ex. 1. Match jobs with descriptions: teacher, doctor, chef.', steps: ['teacher — обучает детей в школе.', 'doctor — лечит больных.', 'chef — готовит блюда в ресторане.'], answer: 'teacher — teaches children, doctor — treats patients, chef — cooks food.' },
  { number: '151', page: 100, condition: 'Ex. 1. Put the verbs in Past Simple: "I (watch) a film yesterday."', steps: ['Past Simple правильных глаголов образуется добавлением -ed.', 'watch → watched.'], answer: 'I <b>watched</b> a film yesterday.' },
  { number: '155', page: 102, condition: 'Ex. 5. Write Past Simple of irregular verbs: go, see, have.', steps: ['go → went (неправильный).', 'see → saw (неправильный).', 'have → had (неправильный).'], answer: 'went, saw, had.' },
  { number: '176', page: 116, condition: 'Ex. 1. Fill in: <i>should/shouldn\'t</i>. "You ___ eat too much sugar."', steps: ['should — совет делать что-то, shouldn\'t — совет не делать.', 'Не есть много сахара — это рекомендация избегать, значит shouldn\'t.'], answer: 'You <b>shouldn\'t</b> eat too much sugar.' },
  { number: '201', page: 132, condition: 'Ex. 1. Write sentences about a hero using: brave, strong, kind.', steps: ['A hero is brave — герой храбрый.', 'A hero is strong — герой сильный.', 'A hero is kind — герой добрый.'], answer: 'A hero is brave, strong and kind.' },
  { number: '221', page: 146, condition: 'Ex. 1. Fill in the missing words: recycle, reuse, reduce.', steps: ['recycle — перерабатывать (бумагу, стекло).', 'reuse — использовать повторно.', 'reduce — уменьшать потребление.'], answer: 'recycle — recycling materials; reuse — using again; reduce — using less.' } ]

// ── Spotlight 6 extra ──
const spotlight6Extra: GdzProblem[  ] = [ { number: '10', page: 10, condition: 'Ex. 3. Write questions. "He can swim." → Can he swim?', steps: ['Вопросительная форма с модальным глаголом can: can + подлежащее + инфинитив.', 'Can he swim?'], answer: 'Can he swim?' },
  { number: '15', page: 13, condition: 'Ex. 2. Present Continuous. "She ___ (read) now." Fill in.', steps: ['Present Continuous: am/is/are + V-ing.', 'She is reading now.'], answer: 'She <b>is reading</b> now.' },
  { number: '20', page: 16, condition: 'Ex. 4. Translate: «Я умею играть на гитаре».', steps: ['Умею = can. Играть на гитаре = play the guitar.', 'I can play the guitar.'], answer: 'I can play the guitar.' },
  { number: '35', page: 25, condition: 'Ex. 3. Write: "What subjects do you study?"', steps: ['do you study — общий вопрос с do для 2-го лица.', 'Ответ: I study Maths, Russian, English, History, etc.'], answer: 'I study Maths, Russian, English and other subjects.' },
  { number: '40', page: 28, condition: 'Ex. 2. Use Past Simple. "We ___ (visit) the museum last week."', steps: ['Past Simple правильных глаголов: V + -ed.', 'visit → visited.'], answer: 'We <b>visited</b> the museum last week.' },
  { number: '56', page: 38, condition: 'Ex. 4. Describe your room. Use "there is" / "there are".', steps: ['Единственное число: There is a bed.', 'Множественное: There are two windows.'], answer: 'There is a desk in my room. There are bookshelves on the wall.' },
  { number: '62', page: 42, condition: 'Ex. 3. Compare using "bigger than / smaller than": elephant, cat, mouse.', steps: ['An elephant is bigger than a cat.', 'A cat is bigger than a mouse.', 'A mouse is the smallest.'], answer: 'An elephant is bigger than a cat. A cat is bigger than a mouse.' },
  { number: '78', page: 52, condition: 'Ex. 2. Write: "Where is the cinema?" Use a map.', steps: ['The cinema is next to / opposite / between...', 'Example: The cinema is next to the park.'], answer: 'The cinema is next to the park.' },
  { number: '105', page: 70, condition: 'Ex. 3. Use "would like to". "What ___ you ___ to do?"', steps: ['would like to = хотел бы.', 'What would you like to do?'], answer: 'What <b>would</b> you <b>like to</b> do?' },
  { number: '130', page: 86, condition: 'Ex. 2. Translate: «Он работает врачом».', steps: ['работает — works (Present Simple, he/she/it + s).', 'врачом = as a doctor.', 'He works as a doctor.'], answer: 'He works as a doctor.' },
  { number: '155', page: 102, condition: 'Ex. 3. Write about yesterday. "Yesterday I ___ (go) to school."', steps: ['go — неправильный глагол: went.', 'Yesterday I went to school.'], answer: 'Yesterday I <b>went</b> to school.' },
  { number: '160', page: 104, condition: 'Ex. 5. Use "will". "In 10 years robots ___ (do) all the work."', steps: ['will + инфинитив = будущее простое.', 'Robots will do all the work.'], answer: 'Robots <b>will do</b> all the work.' },
  { number: '178', page: 118, condition: 'Ex. 3. Modal verbs. "You ___ eat more vegetables." (advice)', steps: ['Совет = should.', 'You should eat more vegetables.'], answer: 'You <b>should</b> eat more vegetables.' },
  { number: '205', page: 134, condition: 'Ex. 2. Passive voice. "The book ___ (write) by Pushkin."', steps: ['Passive: was/were + past participle.', 'write → written.', 'The book was written by Pushkin.'], answer: 'The book <b>was written</b> by Pushkin.' },
  { number: '225', page: 148, condition: 'Ex. 3. Environment. "We must ___ (protect) the rainforests."', steps: ['must + инфинитив (без to).', 'We must protect the rainforests.'], answer: 'We must <b>protect</b> the rainforests.' } ]
