const atanasyan8Extra: GdzProblem[  ] = [ { number: '20', page: 13, condition: 'На рисунке 25 отрезки АВ, ВС, CD и DE равны. Укажите: а) середины отрезков АС, АЕ и СЕ; б) отрезок,', steps: ['Площадь прямоугольника S = a·b.', 'S = 6·8 = 48 см².'], answer: '48 см².' },
  { number: '25', page: 16, condition: 'В квадрате сторона 5 см. Найдите диагональ.', steps: ['d = a√2.', 'd = 5√2 ≈ 7,07 см.'], formulas: ['d = a√2'], answer: '5√2 ≈ 7,07 см.' },
  { number: '30', page: 18, condition: 'Точка В делит отрезок АС на два отрезка. Найдите длину отрезка АС, если АВ = 7,8 см, ВС = 25', steps: ['Средняя линия m = (a+b)/2. 9 = (a+b)/2, a+b = 18.', 'a − b = 4. Решаем: a = 11, b = 7.'], answer: 'Основания 11 и 7 см.' },
  { number: '80', page: 42, condition: 'Известно, что уголAOB = 35°, уголBOC = 50°. Найдите угол АОС. Для каждого из возможных случаев сделайте чертёж с помощью линейки и', steps: ['Половины диагоналей: 5 и x. 5² + x² = 13².', 'x² = 169 − 25 = 144, x = 12. Большая диагональ = 24.', 'S = d₁·d₂/2 = 10·24/2 = 120 см².'], answer: '120 см².' },
  { number: '85', page: 44, condition: 'Докажите, что если биссектрисы углов ABC и CBD перпендикулярны, то точки А, В и D лежат на одной', steps: ['S = ½·a·h = ½·10·6 = 30 см².'], answer: '30 см².' },
  { number: '90', page: 46, condition: 'Сторона АВ треугольника ABC равна 17 см, сторона АС вдвое больше стороны АВ, а сторона ВС на 10 см меньше стороны АС. Найдите периметр треугольника', steps: ['S = ½·a·b (катеты — основание и высота).', 'S = ½·9·12 = 54.'], answer: '54 кв. ед.' },
  { number: '150', page: 78, condition: 'Даны окружность, точка А, не лежащая на ней, и отрезок PQ. Постройте точку М на окружности так, чтобы AM = PQ. Всегда ли задача имеет', steps: ['k² = S₂/S₁ = 16/9.', 'k = 4/3.'], answer: 'k = 4/3.' },
  { number: '155', page: 80, condition: 'Стороны подобных треугольников 4 и 6. Найдите отношение их площадей.', steps: ['k = 6/4 = 3/2. S₂/S₁ = k² = 9/4.'], answer: 'S₂/S₁ = 9/4.' },
  { number: '220', page: 111, condition: 'Докажите, что если при пересечении двух прямых а и b секущей накрест лежащие углы не равны, то прямые а и b', steps: ['d = √(R² − (AB/2)²) = √(25 − 16) = √9 = 3 см.'], answer: '3 см.' },
  { number: '225', page: 113, condition: 'Угол вписан в окружность и опирается на дугу 100°. Найдите угол.', steps: ['Вписанный угол = дуга/2 = 100°/2 = 50°.'], answer: '50°.' },
  { number: '290', page: 146, condition: 'Постройте прямоугольный треугольник: а) по двум катетам; б) по катету и прилежащему к нему острому', steps: ['a − b = (5−2; 3−1) = (3; 2).'], answer: '(3; 2).' },
  { number: '295', page: 148, condition: 'Постройте треугольник по двум сторонам и медиане, проведённой к одной из этих', steps: ['4·a = (4·3; 4·(−2)) = (12; −8).'], answer: '(12; −8).' },
  { number: '340', page: 168, condition: 'Докажите, что четырёхугольник с диагоналями, делящими друг друга пополам, является параллелограммом.', steps: ['Пусть диагонали пересекаются в точке O и делятся пополам.', 'Треугольники AOB и COD равны (по двум сторонам и углу между ними).', 'AB || CD и AB = CD → ABCD параллелограмм.'], answer: 'Признак параллелограмма: диагонали делят друг друга пополам.' } ]

