const ladyzhenskaya8Solutions: GdzProblem[] = [
  { number: '1', page: 3, condition: '1. Прочитайте. Выпишите выделенные словосочетания, называющие различные функции русского', steps: ['Функция общения — язык как средство коммуникации между людьми.', 'Функция сообщения — передача информации.', 'Функция воздействия — влияние на мысли и чувства.'], answer: 'Язык выполняет три функции: общение, сообщение информации и воздействие на читателя/слушателя.' },
  { number: '4', page: 6, condition: '4. Выделите в тексте три абзаца и прочитайте его вслух. Выпишите из каждого абзаца', steps: ['Синтаксис изучает строение словосочетаний и предложений.', 'Пример: «Мальчик бежит» — подлежащее + сказуемое.'], answer: 'Синтаксис — раздел, изучающий словосочетания и предложения.' },
  { number: '10', page: 7, condition: '10. Прочитайте и составьте вопросный план текста. Спишите, расставляя пропущенные знаки', steps: ['Согласование: прилагательное изменяется в роде, числе, падеже по главному слову (существительному).', 'Например: красивый цветок, красивого цветка, красивому цветку.'], answer: 'Пример: красивый цветок. Согласование по роду (м.р.), числу (ед.ч.), падежу (им.п.).' },
  { number: '12', page: 10, condition: '12. Выпишите, расставляя пропущенные запятые, сложные предложения в такой', steps: ['Солнце — подлежащее. Светит — сказуемое.'], answer: 'Грамматическая основа: солнце светит.' },
  { number: '20', page: 11, condition: '20. Диктант. Объясните правописание пропущенных букв. Определите, какие знаки препинания', steps: [ 'Пример: красивого цветка.', 'Красивого — прилагательное Р.п. ед.ч. м.р., цветка — существительное Р.п.' ], answer: 'Например: красивого цветка (управление).' },
  { number: '22', page: 14, condition: '22. Спишите. Обозначьте условия выбора орфограмм на месте скобок. Объясните, почему слова с', steps: ['весело играли — наречие + глагол = словосочетание.'], answer: 'весело играли (наречие + глагол).' },
  { number: '33', page: 18, condition: '33. Прочитайте торжественно стихотворение генерал-полковника Л. Г. Ивашова. Найдите', steps: ['читать (гл.) → книгу (сущ., В.п.) — управление.'], answer: 'Управление.' },
  { number: '40', page: 22, condition: '40. Найдите и выпишите из стихотворения Н. Рубцова (упр. 39) 3 и более многозначных слова;', steps: [ 'Главные слова: ветер, ласкал.', 'Словосочетания: тёплый ветер, летний ветер, ласкал нежно, ласкал листья.' ], answer: 'тёплый ветер, летний ветер, ласкал нежно, ласкал листья.' },
  { number: '66', page: 34, condition: '66. Нормативно ли построение данных словосочетаний? Молодая доцент, внимательная доктор,', steps: ['Главное слово: играли (глагол).', 'Зависимые слова: весело (как? — обстоятельство), в снежки (во что? — дополнение).', 'Словосочетания: играли весело, играли в снежки.'], answer: 'играли весело, играли в снежки.' },
  { number: '70', page: 36, condition: '70. Выпишите словосочетания по образцу. Помните, что грамматическая основа (сочетание', steps: ['Главное слово — читать (глагол).', 'Зависимое слово — книгу (существительное в В.п.).', 'Связь управление (от главного ставим вопрос: читать что? книгу).'], answer: 'Глагольное словосочетание. Вид связи — управление.' },
  { number: '80', page: 42, condition: '80. Прочитайте предложения, делая паузы там, где они обозначены. Как изменяется смысл', steps: ['Главное слово: бежать (глагол).', 'Зависимое: быстро (наречие, неизменяемое).', 'Тип связи: примыкание.'], answer: 'бежать (гл.) ← быстро (нар.), связь: примыкание.' },
  { number: '141', page: 70, condition: '141. К выделенным существительным подберите приложения с теми значениями, которые даны в', steps: ['Подлежащее (кто? что?) — солнце (существительное в И.п.).', 'Сказуемое (что сделало?) — взошло (простое глагольное сказуемое).'], answer: 'Подлежащее — солнце; сказуемое — взошло.' },
  { number: '150', page: 74, condition: '150. Выпишите из учебника истории 7-8 предложений (или отрывок) с обстоятельствами времени. Чем', steps: ['Сказуемое: была тёмной.', 'Состоит из глагола-связки «была» и именной части «тёмной».', 'Тип — составное именное сказуемое.'], answer: 'Составное именное сказуемое.' },
  { number: '160', page: 80, condition: '160. Спишите, расставляя пропущенные знаки препинания. Выполните синтаксический разбор двух', steps: [ 'Казалось — глагол-связка.', 'Бесконечным — именная часть (прилагательное).', 'Казалось бесконечным — составное именное сказуемое.' ], answer: 'Составное именное сказуемое: казалось бесконечным.' },
  { number: '168', page: 86, condition: '168. Прочитайте текст предыдущего упражнения. Чему он посвящён: реформе орфографии или', steps: ['Подлежащее и сказуемое выражены именами существительными.', 'Ставится тире: Математика — наука о числах.'], answer: 'Тире между подл. и сказ. (оба — существительные).' },
  { number: '175', page: 89, condition: '175. Ниже приведены первые строки из рассказов А. Чехова. Начинаются эти рассказы с назывных', steps: ['казался умным — связка «казался» + именная часть «умным» (прил.).', 'Составное именное сказуемое.'], answer: 'казался умным — составное именное сказуемое.' },
  { number: '231', page: 113, condition: '231. Выпишите из учебников биологии, химии, физики предложения с однородными членами,', steps: ['Определение отвечает на вопрос «какой?», «чей?».', '«Старая» — прилагательное, отвечает на вопрос «какая?» — это определение.'], answer: 'Определение — старая (лампа).' },
  { number: '240', page: 117, condition: '240. На месте пропуска употребите предлог в или на согласно нормам литературного языка', steps: ['Дополнение отвечает на вопросы косвенных падежей.', '«Книгу» — отвечает на вопрос «что?» (В.п.) — это дополнение.'], answer: 'Дополнение — книгу.' },
  { number: '250', page: 122, condition: '250. Вставьте на месте пропуска после второй части двойного союза подходящий по смыслу', steps: [ 'Написанное вчера — причастный оборот, выражающий определение.', 'Стоит перед определяемым словом (письмо) → запятыми не выделяется.' ], answer: 'Определение выражено причастным оборотом (написанное вчера).' },
  { number: '258', page: 130, condition: '258. Спишите, расставляя пропущенные разделительные запятые. Какую функцию выполняет союз и,', steps: ['Читаем что? — книгу (В.п.) — дополнение.'], answer: 'книгу — дополнение.' },
  { number: '265', page: 133, condition: '265. Ю. Пименов изображает мир, который мы знаем, но при этом открывает необычное в обычном. В', steps: ['пришёл когда? — вчера (наречие) — обстоятельство времени.'], answer: 'вчера — обстоятельство времени.' },
  { number: '291', page: 143, condition: '291. Прочитайте отрывок из книги Е. Фёдорова об известном металлурге Павле Петровиче Аносове,', steps: ['Второстепенные члены: определение, дополнение, обстоятельство.', 'Определение — какой? чей?', 'Дополнение — кого? чего? (косвенные падежи).', 'Обстоятельство — как? где? когда? почему?'], answer: 'Определение, дополнение, обстоятельство.' },
  { number: '300', page: 148, condition: '300. Запишите предложения, вставляя пропущенные буквы и запятые, раскрывая скобки. Укажите', steps: [ 'Обстоятельство отвечает на вопрос «когда?» → рано утром.', 'Рано — наречие, утром — существительное в Т.п.' ], answer: 'Обстоятельство времени: рано утром.' },
  { number: '310', page: 158, condition: '310. Прочитайте текст о К. Чуковском. Используя приложения, составьте и запишите предложения', steps: ['Причастный оборот после определяемого слова обособляется.', 'Мальчик, увлечённый спортом, занимается каждый день.'], answer: 'Мальчик, увлечённый спортом, занимается каждый день.' },
  { number: '320', page: 162, condition: '320. Прочитайте отрывок из романа И. Ефремова «Лезвие бритвы». Определите тему текста', steps: ['Деепричастный оборот выделяется запятыми.', 'Прочитав книгу, он сделал выводы.'], answer: 'Прочитав книгу, он сделал выводы.' },
  { number: '361', page: 176, condition: '361. Прочитайте, соблюдая интонацию вводности. Какие из выделенных слов выполняют функцию', steps: ['В предложении нет подлежащего и нет возможности его восстановить.', 'Сказуемое — безличный глагол «вечереет».', 'Тип — безличное (односоставное) предложение.'], answer: 'Безличное односоставное предложение.' },
  { number: '370', page: 180, condition: '370. Прочитайте стихотворение К. Бальмонта, обращая внимание на повторяющиеся вводные слова и', steps: ['Сказуемое «люблю» — 1-е лицо, но подлежащего нет.', 'Можно подставить «я» — это определённо-личное предложение.'], answer: 'Определённо-личное предложение.' },
  { number: '380', page: 186, condition: '380. Запишите предложения, включив в них слова будто, как будто, ведь, как раз, всё-таки, вдруг,', steps: [ 'Сказуемое «написали» — 3-е лицо мн.ч.', 'Подлежащее неопределённо (кто написали — неизвестно).', 'Неопределённо-личное предложение.' ], answer: 'Неопределённо-личное предложение.' },
  { number: '390', page: 190, condition: '390. Выборочный диктант. Запишите предложения, осложнённые вводными и вставными', steps: [ 'Предложение состоит только из подлежащего — «тишина».', 'Сказуемого нет. Называет явление, предмет.', 'Это назывное (номинативное) предложение.' ], answer: 'Да, назывное. Выражено только подлежащим.' },
  { number: '431', page: 213, condition: '431. Что обозначают эти сочетания знаков? Подберите и запишите примеры к каждому случаю', steps: ['Три однородных сказуемых без союзов — разделяются запятыми.', 'Дети бегали, прыгали, смеялись.'], answer: 'Дети бегали, прыгали, смеялись.' },
  { number: '440', page: 217, condition: '440. Спишите, расставляя пропущенные знаки завершения, разделения и выделения. Подчеркните', steps: ['«Ребята» — обращение (к кому говорят).', 'Обращение выделяется запятой.', 'Ребята, послушайте меня.'], answer: 'Ребята, послушайте меня.' },
  { number: '450', page: 222, condition: '450. Вставьте пропущенные буквы. Что вам понадобилось определить для того, чтобы правильного', steps: [ '«Как …, так и» — парный союз, запятая ставится перед второй частью.', 'Как ребята, так и взрослые любят кино.' ], answer: 'Как ребята, так и взрослые любят кино.' },
  { number: '460', page: 226, condition: 'Найдите вводное слово и поставьте знаки: «К счастью погода наладилась».', steps: [ '«К счастью» — вводное слово, выражает отношение автора к сказанному.', 'Выделяется запятой: К счастью, погода наладилась.' ], answer: 'К счастью, погода наладилась.' },
  { number: '501', page: 249, condition: 'Произведите синтаксический разбор предложения: «Учитель объяснил новую тему».', steps: ['Подлежащее: учитель (кто?).', 'Сказуемое: объяснил (что сделал?) — ПГС.', 'Дополнение: тему (что?).', 'Определение: новую (какую?).', 'Предложение простое, двусоставное, распространённое.'], answer: 'Простое двусоставное распространённое предложение.' },
  { number: '510', page: 252, condition: 'Составьте схему предложения с обособленным определением: «Листья, покрытые росой, блестели».', steps: [ '[Листья], (покрытые росой), = .', 'Определение выражено причастным оборотом, стоит после определяемого слова.' ], answer: 'Схема: [ –, |прич. об.|, = ]. Запятые выделяют причастный оборот.' },
]
