const peryshkin8Solutions: GdzProblem[] = [
  { number: '1', page: 4, condition: '1. Какими видами механической энергии обладают молекулы вещества вследствие своего', steps: ['T(K) = t(°C) + 273.', 'T = 27 + 273 = 300 К.'], formulas: ['T = t + 273'], answer: '300 К.' },
  { number: '5', page: 7, condition: '1. Летом воздух в здании нагревается, получая энергию различными способами: через стены,', steps: ['Q = c · m · Δt.', 'Δt = 70 − 20 = 50°C.', 'Q = 4200 · 2 · 50 = 420 000 Дж = 420 кДж.'], formulas: ['Q = cmΔt'], answer: '420 кДж.' },
  { number: '10', page: 11, condition: '1. Молот копра при падении ударяет о сваю и забивает её в землю. Какие превращения и переходы', steps: ['Q = c · m · Δt = 460 · 3 · 80 = 110 400 Дж.'], formulas: ['Q = cmΔt'], answer: '110 400 Дж ≈ 110 кДж.' },
  { number: '15', page: 13, condition: '1. Оба термометра в психрометре показывают одинаковую температуру. Какова относительная', steps: ['Q = c·m·Δt = 880·0,5·40 = 17 600 Дж.'], formulas: ['Q = cmΔt'], answer: '17 600 Дж = 17,6 кДж.' },
  { number: '20', page: 18, condition: '1. B ядре атома углерода содержится 12 частиц. Вокруг ядра движутся 6 электронов. Сколько в ядре', steps: ['Теплопроводность — через непосредственный контакт частиц.', 'Конвекция — через движение жидкости или газа.', 'Излучение — через электромагнитные волны, не требует среды.'], answer: 'Излучение.' },
  { number: '25', page: 18, condition: '1. При включении в цепь амперметра так, как показано на рисунке 63, а, сила тока была 0,5 А. Каковы', steps: ['η = Q_полезная / Q_затраченная.', 'η = 800/1000 = 0,8 = 80%.'], formulas: ['η = Q_полезн / Q_затр'], answer: 'КПД = 80%.' },
  { number: '30', page: 22, condition: '1. Длина одного провода 20 см, другого — 1,6 м. Площадь поперечного сечения и материал проводов', steps: ['Испарение — переход молекул с поверхности жидкости в газ.', 'Молекулы имеют разные скорости; часть молекул имеет достаточно энергии, чтобы покинуть жидкость.'], answer: 'Потому что часть молекул на поверхности всегда имеет энергию, достаточную для перехода в газ.' },
  { number: '36', page: 19, condition: '1. Мощность электрического утюга равна 0,6 кВт. Вычислите работу тока в нём за 1,5 ч. Сколько при', steps: ['При нагревании тела его внутренняя энергия увеличивается.', 'Молекулы движутся быстрее, среднее расстояние между ними растёт.'], answer: 'Внутренняя энергия увеличивается.' },
  { number: '42', page: 22, condition: '1. Предложите способ определения полюсов намагниченного стального стержня. 2. Какую форму', steps: ['Q = m·c·ΔT = 2 · 4200 · 20 = 168 000 Дж.'], formulas: ['Q = mcΔT'], answer: 'Q = 168 000 Дж = 168 кДж.' },
  { number: '50', page: 26, condition: 'Что такое теплопроводность? Приведите пример.', steps: ['Теплопроводность — вид теплообмена, при котором энергия передаётся от частицы к частице при непосредственном контакте.', 'Пример: нагрев металлической ложки в горячем чае.'], answer: 'Теплопроводность: теплообмен при непосредственном контакте частиц. Пример: металлическая ложка в чае.' },
  { number: '66', page: 36, condition: 'Железный брусок массой 1 кг расплавили при t = 1539°C. Найдите затраченную теплоту при плавлении. (λ = 270 кДж/кг)', steps: ['Q = λ · m.', 'Q = 270 000 · 1 = 270 000 Дж = 270 кДж.'], formulas: ['Q = λm'], answer: '270 кДж.' },
  { number: '70', page: 38, condition: 'Сколько теплоты выделится при конденсации 0,5 кг пара при 100°C? (r = 2 300 кДж/кг)', steps: ['При конденсации выделяется теплота: Q = r · m.', 'Q = 2 300 000 · 0,5 = 1 150 000 Дж = 1150 кДж.'], formulas: ['Q = rm'], answer: '1150 кДж.' },
  { number: '75', page: 40, condition: 'Найдите количество теплоты при плавлении льда массой 0,2 кг. (λ = 334 000 Дж/кг)', steps: ['Q = λ·m = 334 000·0,2 = 66 800 Дж.'], formulas: ['Q = λm'], answer: '66 800 Дж ≈ 66,8 кДж.' },
  { number: '80', page: 44, condition: 'Назовите виды теплопередачи. Приведите примеры.', steps: ['Теплопроводность — передача тепла через контакт частиц (нагрев металлической ложки в горячем чае).', 'Конвекция — передача тепла через движение жидкости/газа (тёплый воздух от батареи поднимается).', 'Излучение — через электромагнитные волны (тепло от Солнца).'], answer: 'Теплопроводность, конвекция, излучение.' },
  { number: '88', page: 46, condition: 'Теплота плавления льда: q = 334 кДж/кг. Сколько теплоты нужно для плавления 3 кг льда?', steps: ['Q = m·q = 3 · 334 000 = 1 002 000 Дж ≈ 1 МДж.'], formulas: ['Q = mq'], answer: 'Q = 1 002 кДж ≈ 1 МДж.' },
  { number: '95', page: 50, condition: 'Что называется точкой кипения? Как она зависит от давления?', steps: ['Точка кипения — температура, при которой жидкость кипит при данном давлении.', 'При увеличении давления точка кипения повышается.'], answer: 'Точка кипения растёт с давлением.' },
  { number: '131', page: 67, condition: 'Сила тока в проводнике 2 А, время — 5 с. Найдите заряд, прошедший через сечение.', steps: ['q = I · t.', 'q = 2 · 5 = 10 Кл.'], formulas: ['q = It'], answer: '10 Кл.' },
  { number: '135', page: 69, condition: 'Напряжение на лампе 220 В, сила тока 0,5 А. Найдите сопротивление лампы.', steps: ['По закону Ома: R = U / I.', 'R = 220 / 0,5 = 440 Ом.'], formulas: ['R = U/I (закон Ома)'], answer: '440 Ом.' },
  { number: '140', page: 71, condition: 'Два сопротивления 4 Ом и 6 Ом включены последовательно. Найдите общее сопротивление.', steps: ['При последовательном соединении: R = R₁ + R₂.', 'R = 4 + 6 = 10 Ом.'], formulas: ['R = R₁ + R₂'], answer: '10 Ом.' },
  { number: '145', page: 73, condition: 'Два сопротивления 4 Ом и 12 Ом включены параллельно. Найдите общее сопротивление.', steps: ['1/R = 1/R₁ + 1/R₂ = 1/4 + 1/12 = 3/12 + 1/12 = 4/12 = 1/3.', 'R = 3 Ом.'], formulas: ['1/R = 1/R₁ + 1/R₂'], answer: '3 Ом.' },
  { number: '150', page: 75, condition: 'Мощность утюга 1000 Вт, напряжение 220 В. Найдите силу тока.', steps: ['P = U · I, следовательно I = P / U.', 'I = 1000 / 220 ≈ 4,5 А.'], formulas: ['P = UI, I = P/U'], answer: '≈ 4,5 А.' },
  { number: '155', page: 80, condition: 'Напряжение 120 В, сила тока 3 А. Найдите сопротивление и мощность.', steps: ['R = U/I = 120/3 = 40 Ом.', 'P = U·I = 120·3 = 360 Вт.'], formulas: ['R = U/I', 'P = UI'], answer: 'R = 40 Ом, P = 360 Вт.' },
  { number: '160', page: 83, condition: 'Сила тока 2 А, сопротивление 5 Ом. Найдите напряжение и мощность.', steps: ['U = I·R = 2·5 = 10 В.', 'P = I²·R = 4·5 = 20 Вт.'], formulas: ['U = IR', 'P = I²R'], answer: 'U = 10 В, P = 20 Вт.' },
  { number: '165', page: 86, condition: 'Найдите работу тока за 10 минут при U = 220 В и I = 5 А.', steps: ['A = P·t = U·I·t.', 'A = 220·5·600 = 660 000 Дж = 660 кДж.'], formulas: ['A = UIt'], answer: '660 000 Дж = 660 кДж.' },
  { number: '172', page: 88, condition: 'Закон Ома для участка цепи. Ток I=2 А, R=10 Ом. Напряжение?', steps: ['U = I·R = 2·10 = 20 В.'], formulas: ['U = IR'], answer: 'U = 20 В.' },
  { number: '180', page: 92, condition: 'Последовательное соединение: R₁=4 Ом, R₂=6 Ом. Общее сопротивление?', steps: ['R = R₁ + R₂ = 4 + 6 = 10 Ом.'], answer: 'R = 10 Ом.' },
  { number: '188', page: 96, condition: 'Параллельное соединение: R₁=6 Ом, R₂=3 Ом. Найдите общее сопротивление.', steps: ['1/R = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2.', 'R = 2 Ом.'], answer: 'R = 2 Ом.' },
  { number: '226', page: 113, condition: 'Через проводник с током течёт ток 3 А. Опишите магнитное поле вокруг него.', steps: ['По правилу буравчика: вокруг проводника возникает кольцеобразное магнитное поле.', 'Направление силовых линий определяется правилом правой руки.'], answer: 'Вокруг проводника с током возникает кольцевое магнитное поле (правило правой руки/буравчика).' },
  { number: '235', page: 118, condition: 'Объясните явление электромагнитной индукции.', steps: ['Если магнитный поток через катушку изменяется, в ней возникает ЭДС индукции.', 'Это явление было открыто Фарадеем в 1831 году.'], answer: 'Электромагнитная индукция — возникновение ЭДС в проводнике при изменении магнитного потока.' },
  { number: '243', page: 124, condition: 'Что такое электромагнитная индукция? Кто открыл?', steps: ['Электромагнитная индукция — возникновение тока в замкнутом контуре при изменении магнитного потока.', 'Открыл Майкл Фарадей в 1831 году.'], answer: 'Возникновение ЭДС при изменении магнитного потока; открыл Фарадей.' },
  { number: '286', page: 143, condition: 'Угол падения луча на плоское зеркало равен 30°. Найдите угол отражения.', steps: ['Закон отражения: угол отражения равен углу падения.', 'Угол отражения = 30°.'], formulas: ['∠падения = ∠отражения'], answer: '30°.' },
  { number: '290', page: 145, condition: 'Луч переходит из воды (n = 1,33) в воздух (n = 1). Угол падения 30°. Определите поведение луча.', steps: ['При переходе из более плотной среды в менее плотную луч преломляется, отходя от нормали.', 'Угол преломления > угла падения.'], answer: 'Луч отклонится от нормали, угол преломления > 30°.' },
  { number: '295', page: 148, condition: 'Луч падает на плоскую поверхность под углом 45°. Найдите угол между падающим и отражённым лучами.', steps: ['Угол падения = угол отражения = 45°.', 'Угол между падающим и отражённым: 45° + 45° = 90°.'], answer: '90°.' },
  { number: '305', page: 153, condition: 'Предмет находится в воде (n = 1,33). Луч выходит в воздух. Что произойдёт с углом?', steps: ['Переход из воды в воздух — из более плотной в менее плотную среду.', 'Угол преломления больше угла падения.'], answer: 'Угол преломления будет больше угла падения (луч отклоняется от нормали).' },
  { number: '312', page: 158, condition: 'Угол преломления 30°, угол падения 45°. Найдите показатель преломления.', steps: ['n = sin(45°)/sin(30°) = (√2/2)/(1/2) = √2 ≈ 1,41.'], formulas: ['n = sinα/sinβ'], answer: 'n = √2 ≈ 1,41.' },
  { number: '320', page: 162, condition: 'Линза с фокусным расстоянием 20 см. Предмет на расстоянии 30 см. Где изображение?', steps: ['1/v = 1/F − 1/u = 1/20 − 1/30 = 3/60 − 2/60 = 1/60.', 'v = 60 см.'], formulas: ['1/v + 1/u = 1/F'], answer: 'v = 60 см.' },
]
