const atanasyan11Solutions: GdzProblem[] = [
  { number: '1', page: 4, condition: 'По рисунку 8 назовите: а) плоскости, в которых лежат прямые PE, MK, DB, AB, ЕС; б) точки пересечения', steps: ['Куб имеет 6 одинаковых граней. S = 6a².', 'S = 6 · 25 = 150 см².'], formulas: ['S = 6a²'], answer: '150 см².' },
  { number: '2', page: 5, condition: 'По рисунку 9 назовите: а) точки, лежащие в плоскостях DCC1 и BQC; б) плоскости, в которых лежит', steps: ['Уравнение: 2(x−1) − 1(y−2) + 1(z−3) = 0.', '2x − 2 − y + 2 + z − 3 = 0.', '2x − y + z − 3 = 0.'], answer: '2x − y + z − 3 = 0.' },
  { number: '4', page: 6, condition: 'Точки А, В, C и D не лежат в одной плоско- сти. а) Могут ли какие-то три из них лежать на одной прямой? б) Могут ли прямые AB и CD пересекаться? Ответ', steps: ['x + 2y + 3z = 0.'], answer: 'x + 2y + 3z = 0.' },
  { number: '5', page: 8, condition: 'Докажите, что через три данные точки, лежащие на прямой, проходит плоскость. Сколько существует таких', steps: ['S_бок = 2πRh = 2π · 4 · 7 = 56π ≈ 175,9.'], formulas: ['Sбок = 2πRh'], answer: '56π ≈ 176 кв. ед.' },
  { number: '6', page: 9, condition: 'Три данные точки соединены попарно отрезками. Докажите, что все отрезки лежат в одной', steps: ['d = |2·1 − 2 + 2·3 − 6| / √(4 + 1 + 4) = |2 − 2 + 6 − 6| / 3 = 0 / 3 = 0.'], answer: 'd = 0 (точка лежит в плоскости).' },
  { number: '8', page: 10, condition: 'Верно ли утверждение: а) если две точки окружности лежат в плоскости, то и вся окружность', steps: ['d = √((4−1)²+(6−2)²+(3−3)²) = √(9+16+0) = √25 = 5.'], answer: '5.' },
  { number: '10', page: 12, condition: 'Верно ли, что прямая лежит в плоскости данного треугольника, если она: а) пересекает две стороны треугольника; б) проходит через одну из вершин', steps: ['Сечение через центр — большой круг радиуса R = 10.', 'S = π · 10² = 100π ≈ 314.'], answer: '100π ≈ 314 кв. ед.' },
  { number: '12', page: 14, condition: 'Точки А, В, С, D не лежат в одной плоскости. Пересекаются ли плоскости, проходящие через точки А, В, C и А, В,', steps: ['cos φ = |a·b| / (|a|·|b|) = |1+0+0| / (√2·√2) = 1/2.', 'φ = 60°.'], answer: 'φ = 60°.' },
  { number: '15', page: 14, condition: 'Три прямые попарно пересекаются. Докажите, что они либо лежат в одной плоскости, либо имеют общую', steps: ['Ось Ox: e=(1,0,0).', 'cos φ = a·e / (|a||e|) = 1/(√2·1) = 1/√2.', 'φ = 45°.'], answer: '45°.' },
  { number: '20', page: 21, condition: 'Средняя линия трапеции лежит в плоскости а. Пересекают ли прямые, содержащие ее основания, плоскость а? Ответ', steps: ['S = 4πR² = 36π → R² = 9, R = 3.', 'V = (4/3)πR³ = (4/3)π·27 = 36π ≈ 113.'], answer: '36π ≈ 113 куб. ед.' },
  { number: '22', page: 18, condition: 'Точки A и B лежат в плоскости а, a точка C не лежит в этой плоскости. Докажите, что прямая, проходящая через середины отрезков AC и ВС, параллельна плоскости', steps: ['(x−2)² + (y+1)² + (z−3)² = 16.'], answer: '(x−2)² + (y+1)² + (z−3)² = 16.' },
  { number: '44', page: 27, condition: 'Прямые OB и CD параллельные, а OA и CD — скрещивающиеся прямые. Найдите угол между прямыми OA и CD, если: а) ZAOB = 40°; б) ZAOB = 135°; в) ZAOB =', steps: ['V = πR²h = π·9·10 = 90π ≈ 282,7.'], formulas: ['V = πR²h'], answer: '90π ≈ 283 куб. ед.' },
  { number: '48', page: 29, condition: 'Найдите объём цилиндра, вписанного в куб с ребром 6.', steps: ['R = 3, h = 6.', 'V = πR²h = π·9·6 = 54π ≈ 169,6.'], answer: '54π ≈ 170 куб. ед.' },
  { number: '55', page: 34, condition: 'Докажите, что если прямая а пересекает плоскость а, то она пересекает также любую плоскость,', steps: ['Конус имеет те же R и h.', 'V_кон = (1/3)V_цил = (1/3)·πR²h = (1/3)·π·16·6 = 32π.'], answer: '32π ≈ 100,5 куб. ед.' },
  { number: '58', page: 36, condition: 'Докажите, что если плоскость у пересекает одну из параллельных плоскостей а и p, то она', steps: ['R = 2, h = 4.', 'V = (1/3)πR²h = (1/3)·π·4·4 = 16π/3 ≈ 16,8.'], answer: '16π/3 ≈ 16,8 куб. ед.' },
  { number: '70', page: 42, condition: 'Докажите, что плоскость, проходящая через середины ребер AB, AC и AD тетраэдра ABCD, параллельна плоскости', steps: ['R = a/2 = 4 см.', 'V = (4/3)πR³ = (4/3)π·64 = 256π/3 ≈ 268.'], answer: '256π/3 ≈ 268 куб. ед.' },
  { number: '72', page: 43, condition: 'Изобразите тетраэдр DABC и постройте сечение этого тетраэдра плоскостью, проходящей через', steps: ['V = (2/3)πR²h = (2/3)·π·36·2 = 48π ≈ 150,8.'], answer: '48π ≈ 151 куб. ед.' },
  { number: '85', page: 50, condition: 'Изобразите параллелепипед ABCDA1B1C1D1 и постройте его сечение плоскостью BKL, где точка K —', steps: ['V = πh²(R − h/3) = π·9·(5 − 1) = 36π ≈ 113.'], formulas: ['V = πh²(R − h/3)'], answer: '36π ≈ 113 куб. ед.' },
  { number: '105', page: 60, condition: 'Изобразите тетраэдр DABC и отметьте точки M и N на ребрах BD и CD и внутреннюю точку K грани ABC. Постройте сечение тетраэдра плоскостью', steps: ['Объёмы подобных тел относятся как k³.', 'k³ = 27.'], answer: 'В 27 раз.' },
  { number: '108', page: 62, condition: 'B тетраэдре DABC биссектрисы трех углов при вершине D пересекают отрезки ВС, CA и AB', steps: ['S = 5² = 25.', 'V = 25·8 = 200.'], answer: '200 куб. ед.' },
  { number: '115', page: 66, condition: 'Точка M лежит на ребре BC параллелепипеда ABCDA1B1C1D1. Постройте сечение этого параллелепипеда плоскостью, проходящей через точку M параллельно плоскости', steps: ['S = (√3/4)·36 = 9√3.', 'V = (1/3)·9√3·4 = 12√3 ≈ 20,8.'], answer: '12√3 ≈ 20,8 куб. ед.' },
  { number: '120', page: 68, condition: 'Через точку O пересечения диагоналей квадрата, сторона которого равна а, проведена прямая OK,', steps: ['S_осн = (3√3/2)·a² = (3√3/2)·16 = 24√3.', 'V = 24√3 · 5 = 120√3 ≈ 207,8.'], answer: '120√3 ≈ 208 куб. ед.' },
  { number: '140', page: 78, condition: 'Из точки А, не принадлежащей плоскости а, проведены к этой плоскости перпендикуляр AO и две', steps: ['V = (a³√2)/12 = (216√2)/12 = 18√2 ≈ 25,5.'], formulas: ['V = a³√2/12'], answer: '18√2 ≈ 25,5 куб. ед.' },
  { number: '145', page: 82, condition: 'Через вершину A прямоугольного треугольника ABC с прямым углом C проведена прямая AD,', steps: ['4πR² = 100π → R² = 25 → R = 5.', 'V = (4/3)πR³ = (4/3)π·125 = 500π/3 ≈ 524.'], answer: '500π/3 ≈ 524 куб. ед.' },
  { number: '163', page: 90, condition: 'Наклонная AM, проведенная из точки A к данной плоскости, равна d. Чему равна проекция этой', steps: ['V_куба = a³; V_тетраэдра = a³√2/12.', 'Если равны: a_куба³ = a_тетр³·√2/12.', 'a_тетр/a_куба = (12/√2)^(1/3) = (6√2)^(1/3).'], answer: 'a_тетр = a_куба · (6√2)^(1/3).' },
]
