const merzlyak5Extra2: GdzProblem[  ] = [ { number: '82', page: 42, condition: 'В магазин привезли 240 кг бананов и 156 кг апельсинов. Треть привезённых фруктов продали в', steps: ['39 = 3 · 13. Имеет делители помимо 1 и себя → составное.'], answer: 'Да, 39 — составное (39 = 3·13).' },
  { number: '86', page: 44, condition: 'Проведите произвольную прямую и отметьте на ней точки А, В и С. Запишите все возможные обозначения этой', steps: ['36 = 1·36 = 2·18 = 3·12 = 4·9 = 6·6.', 'Делители: 1, 2, 3, 4, 6, 9, 12, 18, 36.'], answer: '1, 2, 3, 4, 6, 9, 12, 18, 36.' },
  { number: '92', page: 47, condition: 'Признак делимости на 9: проверьте число 873.', steps: ['Сумма цифр: 8+7+3 = 18. 18 делится на 9.', '873 делится на 9.'], answer: '873 делится на 9.' },
  { number: '100', page: 51, condition: 'Точки M, К и N лежат на одной прямой. Найдите длину отрезка КN, если МК = 15 см, MN = 6', steps: ['48 = 2⁴·3, 36 = 2²·3².', 'НОД = 2²·3 = 12.'], answer: '12.' },
  { number: '158', page: 76, condition: 'Запишите в виде двойного неравенства утверждения: 1) число 56 больше 52 и меньше 58; 2) число 258', steps: ['5/8 = 25/40; 3/5 = 24/40.', '25/40 > 24/40 → 5/8 > 3/5.'], answer: '5/8 > 3/5.' },
  { number: '165', page: 80, condition: 'Знаменитый университет Сорбонна, находящийся в Париже (Франция), основан в 1215 г. Он основан', steps: ['НОК(3,4) = 12. 2/3 = 8/12; 1/4 = 3/12.', '8/12 + 3/12 = 11/12.'], answer: '11/12.' },
  { number: '172', page: 84, condition: 'Используйте свойства сложения при вычислении суммы: 1) (146 + 322) + 178; 3) 625 + 481 + 75 + 219; 2) 784 + (179 + 116); 4) 427 + 88 + 273 +', steps: ['3·8 / 4·9 = 24/36 = 2/3.'], answer: '2/3.' },
  { number: '180', page: 88, condition: 'Поезд отправляется от станции А в 9 ч 57 мин и прибывает на станцию В через 2 ч 36 мин. В котором часу поезд прибывает на станцию', steps: ['5/6 · 3/5 = 15/30 = 1/2.'], answer: '1/2.' },
  { number: '385', page: 186, condition: 'Выполните умножение: 1) 516·32; 4) 314·258; 7) 626·480; 2) 418·46; 5) 133·908; 8) 1 234·567; 3) 4 519·52; 6) 215·204; 9) 2 984·4', steps: ['Ромб имеет 4 равные стороны: P = 4·7 = 28 см.'], answer: '28 см.' },
  { number: '392', page: 190, condition: 'Выполните умножение: 1) 214·10; 3) 10 000·546; 5) 580·240; 2) 100·328; 4) 140·80; 6) 270·3', steps: ['Куб — прямоугольный параллелепипед.', 'Число вершин: 8.'], answer: '8.' },
  { number: '396', page: 192, condition: 'Путешественник плыл на моторной лодке 5 ч по реке со скоростью 27 км/ч и 7 ч по озеру со', steps: ['V = a³ = 4³ = 64 см³.'], answer: '64 см³.' },
  { number: '476', page: 230, condition: 'Расстояние между городками Сен-Жермен и Сен-Антуан равно 12 лье (старинная французская', steps: ['0,15 · 200 = 30.'], answer: '30.' },
  { number: '480', page: 232, condition: 'Буратино живёт на расстоянии 1 км 200 м от школы. Уроки в школе начинаются в 8 ч 30 мин. Буратино', steps: ['Повышение = 1500 · 0,1 = 150. Новая цена = 1650 руб.'], answer: '1650 руб.' },
  { number: '543', page: 262, condition: 'Докажите, что последняя цифра числа а равна остатку при делении этого числа на', steps: ['3,60 + 2,85 = 6,45.'], answer: '6,45.' },
  { number: '548', page: 264, condition: 'Назовите основание и показатель степени: 1) 4^8; 3) a^9; 5) 2^39; 2) 13^10; 4) 6^m; 6)', steps: ['48 · 25 = 1200. Знаков после запятой: 1+1=2.', '4,8 · 2,5 = 12,00 = 12.'], answer: '12.' } ]
