const makarychev7Extra: GdzProblem[  ] = [ { number: '25', page: 16, condition: 'Докажите тождество: <b>(a+b)² = a²+2ab+b²</b>. Проверьте при a=2, b=3.', steps: ['(2+3)² = 5² = 25.', 'a²+2ab+b² = 4+12+9 = 25. ✓'], answer: 'Тождество верно: при a=2, b=3 обе части = 25.' },
  { number: '30', page: 18, condition: 'Решите уравнение: <b>4x − 3 = 2x + 7</b>.', steps: ['4x − 2x = 7 + 3.', '2x = 10, x = 5.'], answer: 'x = 5.' },
  { number: '35', page: 20, condition: 'Решите уравнение: <b>3(x − 2) = 9</b>.', steps: ['x − 2 = 3.', 'x = 5.'], answer: 'x = 5.' },
  { number: '45', page: 26, condition: 'Составьте уравнение и решите задачу: сумма двух чисел 28, второе в 3 раза больше первого.', steps: ['Первое число x, второе 3x.', 'x + 3x = 28. 4x = 28. x = 7.', 'Числа: 7 и 21.'], answer: '7 и 21.' },
  { number: '60', page: 44, condition: 'Является ли точка A(2, 3) точкой графика функции <b>y = 2x − 1</b>?', steps: ['Подставляем x=2: y = 2·2−1 = 3.', 'y=3 совпадает с координатой точки A(2,3). ✓'], answer: 'Да, точка A(2,3) лежит на графике.' },
  { number: '65', page: 46, condition: 'На выборах голоса за двух кандидатов распределились в отношении 5:7. Всего в голосовании приняли участие 252 человека. Сколько голосов набрал победитель?', steps: ['При x=0: y = 0 + 2 = 2.', 'Точка пересечения с осью y: (0; 2).'], answer: '(0; 2).' },
  { number: '70', page: 48, condition: 'Найдите точку пересечения прямой <b>y = 3x − 6</b> с осью x.', steps: ['При y=0: 0 = 3x − 6. 3x = 6. x = 2.', 'Точка: (2; 0).'], answer: '(2; 0).' },
  { number: '115', page: 80, condition: 'Вычислите: <b>(x²)³</b> при x = 2.', steps: ['(x²)³ = x⁶. При x=2: 2⁶ = 64.'], answer: '64.' },
  { number: '120', page: 82, condition: 'Упростите: <b>a⁴ · a² : a³</b>.', steps: ['a⁴ · a² = a⁶. a⁶ : a³ = a³.'], answer: 'a³.' },
  { number: '125', page: 84, condition: 'Вычислите: <b>(-2)⁴</b>.', steps: ['(−2)⁴ = (−2)·(−2)·(−2)·(−2) = 16. (Чётная степень → плюс.)'], answer: '16.' },
  { number: '175', page: 120, condition: 'Сложите многочлены: <b>(3x² − 2x + 1) + (x² + 5x − 3)</b>.', steps: ['Группируем: (3x²+x²) + (−2x+5x) + (1−3).', '= 4x² + 3x − 2.'], answer: '4x² + 3x − 2.' },
  { number: '180', page: 122, condition: 'Умножьте: <b>3x(2x − 5)</b>.', steps: ['3x · 2x − 3x · 5 = 6x² − 15x.'], answer: '6x² − 15x.' },
  { number: '185', page: 124, condition: 'Найдите значение выражения -0,5(7b - 12а) - (8,4а - 14b) при a = -10, b = - 6 .', steps: ['Разность квадратов: (a+b)(a−b) = a²−b².', 'x² − 4.'], formulas: ['(a+b)(a−b) = a²−b²'], answer: 'x² − 4.' },
  { number: '190', page: 126, condition: 'Раскройте скобки: <b>(x + 3)²</b>.', steps: ['(a+b)² = a²+2ab+b².', 'x² + 6x + 9.'], answer: 'x² + 6x + 9.' },
  { number: '235', page: 160, condition: 'Разложите на множители: <b>a² − 16</b>.', steps: ['a² − 16 = a² − 4² = (a−4)(a+4).'], answer: '(a−4)(a+4).' },
  { number: '240', page: 162, condition: 'Разложите на множители: <b>x² + 10x + 25</b>.', steps: ['25 = 5², 10x = 2·x·5 → полный квадрат.', 'x² + 10x + 25 = (x+5)².'], answer: '(x+5)².' },
  { number: '245', page: 164, condition: 'Разложите на множители: <b>4x² − 12x + 9</b>.', steps: ['(2x)² − 2·2x·3 + 3² = (2x−3)².'], answer: '(2x−3)².' },
  { number: '250', page: 166, condition: 'Упростите: <b>(x+2)² − (x−2)²</b>.', steps: ['= (x²+4x+4) − (x²−4x+4).', '= 8x.'], answer: '8x.' } ]
