const makarychev7Extra2: GdzProblem[  ] = [ { number: '295', page: 193, condition: '295. В автопарке было в 1,5 раза больше грузовых машин, чем лег­ковы х. После того как автопарк получил ещё 45 легковых автомашин, а 12 грузовых машин передал фермерам, в нём стало легковых машин на 17 больше, чем грузовы х. Сколько всего автомашин было в автопарке?', steps: ['Сложим уравнения: 2x = 6 → x = 3.', 'y = 5 − 3 = 2.'], answer: 'x = 3, y = 2.' },
  { number: '300', page: 196, condition: 'Решите систему подстановкой: <b>{ y = 2x; x + y = 9 }</b>.', steps: ['Подставим y = 2x: x + 2x = 9.', '3x = 9 → x = 3, y = 6.'], answer: 'x = 3, y = 6.' },
  { number: '305', page: 198, condition: '(Для работы в парах.) Покажите схематически, как располо­жен график функции, заданной формулой: а) у = 1,7х ; б) y = -3,1x; в) у = 0,9х; г) у = -2 ,3х; д) у = kx, где k > 0; e ) y = kx, где k < 0. 1) Распределите, кто выполняет задания а), б), а кто — зада­ния в), г), и выполните их. 2) Проверьте друг у друга правильность выполнения заданий. 3) Обсудите, какой вид имеет график функции y = kx в зада­ниях д) и е).', steps: ['Сложим: 3x = 9 → x = 3.', 'y = 3 − 2 = 1.'], answer: 'x = 3, y = 1.' },
  { number: '310', page: 200, condition: 'Решите систему методом сложения: <b>{ 3x + 2y = 16; x − 2y = 0 }</b>.', steps: ['Сложим: 4x = 16 → x = 4.', 'x − 2y = 0: 4 = 2y → y = 2.'], answer: 'x = 4, y = 2.' },
  { number: '315', page: 202, condition: 'Составьте систему и решите задачу: два числа в сумме 20, разность 4.', steps: ['{ x + y = 20; x − y = 4 }.', 'Сложим: 2x = 24 → x = 12, y = 8.'], answer: 'Числа 12 и 8.' },
  { number: '320', page: 205, condition: 'Решите систему: <b>{ 5x − 3y = 1; 2x + y = 8 }</b>.', steps: ['Из второго: y = 8 − 2x.', 'Подставим: 5x − 3(8−2x) = 1 → 5x − 24 + 6x = 1 → 11x = 25 → x = 25/11.', 'Нецелое решение. Проверим: возможно другое: 5x−3y=1; 2x+y=8. 3·(2x+y)=24 → 6x+3y=24. Сложим: 11x=25.', 'x=25/11, y=8−50/11=38/11.'], answer: 'x = 25/11, y = 38/11.' },
  { number: '325', page: 208, condition: '325. В одной и той же координатной плоскости постройте графики функций у = 6, = 3,2, = -1, у = - 5, у = 0.', steps: ['{ a + b = 14; a − b = 4 }.', 'a = 9, b = 5.'], answer: 'Стороны 9 см и 5 см.' },
  { number: '330', page: 210, condition: '330. График функции у = kx + 2 5 / 8 проходит через точку (8; - 3 / 8 ) Найдите коэффициент k.', steps: ['Из первого: y = 4x − 9.', 'Подставим: 2x + 3(4x−9) = 17 → 2x + 12x − 27 = 17 → 14x = 44 → x = 22/7.', 'Упрощаем: x = 22/7 ≈ 3,14; y = 4·22/7 − 9 = 88/7 − 63/7 = 25/7.'], answer: 'x = 22/7, y = 25/7.' },
  { number: '335', page: 213, condition: 'Решите систему: <b>{ x + 2y = 10; 3x − y = 5 }</b>.', steps: ['Из первого: x = 10 − 2y.', 'Подставим: 3(10−2y) − y = 5 → 30 − 6y − y = 5 → 7y = 25 → y = 25/7.', 'x = 10 − 50/7 = 20/7.'], answer: 'x = 20/7, y = 25/7.' },
  { number: '350', page: 220, condition: 'Касса продала 120 билетов на сумму 4800 руб. Цена одного вида 30 руб., другого — 50 руб. Сколько продано билетов каждого вида?', steps: ['{ x + y = 120; 30x + 50y = 4800 }.', 'x = 120 − y. 30(120−y) + 50y = 4800 → 3600 + 20y = 4800 → 20y = 1200 → y = 60.', 'x = 60.'], answer: 'По 60 билетов каждого вида.' },
  { number: '360', page: 226, condition: 'Два рабочих вместе изготавливают деталь за 4 ч. Первый рабочий сделал бы её один за 6 ч. За сколько часов изготовит деталь второй рабочий?', steps: ['1/6 + 1/t = 1/4.', '1/t = 1/4 − 1/6 = 3/12 − 2/12 = 1/12.', 't = 12 ч.'], answer: '12 часов.' },
  { number: '370', page: 232, condition: 'Упростите: <b>(2a + b)² − (2a − b)²</b>.', steps: ['= (4a² + 4ab + b²) − (4a² − 4ab + b²).', '= 8ab.'], answer: '8ab.' },
  { number: '375', page: 235, condition: 'Разложите на множители: <b>x³ − x</b>.', steps: ['x³ − x = x(x² − 1) = x(x−1)(x+1).'], answer: 'x(x−1)(x+1).' },
  { number: '380', page: 238, condition: 'Решите уравнение: <b>x² − 7x + 12 = 0</b>.', steps: ['Ищем два числа с суммой 7 и произведением 12: 3 и 4.', 'x² − 7x + 12 = (x−3)(x−4) = 0.', 'x = 3 или x = 4.'], answer: 'x = 3; x = 4.' },
  { number: '385', page: 240, condition: 'Докажите тождество: <b>(a + b)² = (a − b)² + 4ab</b>.', steps: ['(a+b)² = a²+2ab+b².', '(a−b)²+4ab = a²−2ab+b²+4ab = a²+2ab+b².', 'Тождество доказано.'], answer: 'Доказано.' } ]
