const atanasyan7Extra: GdzProblem[  ] = [ { number: '6', page: 9, condition: 'Проведите прямую и отметьте на ней три точки. Сколько отрезков получилось на', steps: ['Смежные углы в сумме 180°.', '180° − 65° = 115°.'], answer: '115°.' },
  { number: '7', page: 9, condition: 'На рисунке 10 изображена прямая, на ней отмечены точки А, В, С и D. Назовите все отрезки: а) на которых лежит точка С; б) на которых не лежит точка', steps: ['Вертикальные углы AOB и COD равны.', 'COD = 72°.'], answer: '72°.' },
  { number: '9', page: 10, condition: 'Биссектриса угла делит его пополам. Угол ABC = 80°. Найдите каждую половину.', steps: ['80° : 2 = 40°.'], answer: '40°.' },
  { number: '42', page: 30, condition: 'В треугольнике два угла 60° и 70°. Найдите третий.', steps: ['Сумма углов треугольника = 180°.', '180° − 60° − 70° = 50°.'], answer: '50°.' },
  { number: '45', page: 32, condition: 'Треугольник равнобедренный, основание 6 см, боковая сторона 9 см. Найдите периметр.', steps: ['P = 6 + 9 + 9 = 24 см.'], answer: '24 см.' },
  { number: '48', page: 34, condition: 'В равностороннем треугольнике все углы равны. Найдите каждый.', steps: ['180° : 3 = 60°.'], answer: '60°.' },
  { number: '50', page: 35, condition: 'Медиана треугольника делит его на два треугольника. Каковы их площади?', steps: ['Медиана делит треугольник на два треугольника с равными площадями.', 'Каждый = S/2.'], answer: 'Площади равны: S/2 каждый.' },
  { number: '82', page: 70, condition: 'Прямые a ∥ b. Секущая пересекает их. Накрест лежащие углы равны?', steps: ['По признаку параллельных прямых: накрест лежащие углы равны.', 'Да, равны.'], answer: 'Да, равны.' },
  { number: '85', page: 72, condition: 'Сумма односторонних углов при параллельных прямых. Один угол 110°. Найдите второй.', steps: ['Односторонние углы в сумме 180°.', '180° − 110° = 70°.'], answer: '70°.' },
  { number: '88', page: 74, condition: 'Докажите, что углы a и b — соответственные, если a ∥ b. Что можно сказать о них?', steps: ['Соответственные углы при параллельных прямых равны.', 'a = b.'], answer: 'Соответственные углы равны.' },
  { number: '122', page: 102, condition: 'Найдите гипотенузу прямоугольного треугольника с катетами 5 и 12.', steps: ['c² = a² + b² = 25 + 144 = 169.', 'c = 13.'], formulas: ['c² = a²+b²'], answer: '13.' },
  { number: '125', page: 104, condition: 'Катет прямоугольного треугольника 8, гипотенуза 10. Найдите второй катет.', steps: ['b² = c² − a² = 100 − 64 = 36.', 'b = 6.'], answer: '6.' },
  { number: '128', page: 106, condition: 'Является ли тройка (9, 40, 41) пифагоровой?', steps: ['9² + 40² = 81 + 1600 = 1681 = 41².', 'Да, является пифагоровой тройкой.'], answer: 'Да.' },
  { number: '130', page: 108, condition: 'В равнобедренном треугольнике основание 8 см, боковые стороны 5 см. Найдите высоту, опущенную на основание.', steps: ['Высота делит основание пополам: 4 см.', 'h² = 5² − 4² = 25−16 = 9. h = 3 см.'], answer: '3 см.' },
  { number: '155', page: 132, condition: 'Два треугольника конгруэнтны. Первый: AB=5, BC=7, AC=6. Каковы стороны второго?', steps: ['При конгруэнтности (равенстве) все соответственные стороны равны.', 'Стороны второго: 5, 7, 6.'], answer: 'Стороны второго треугольника: 5, 7, 6.' } ]
